UPDATE SWC_MENU SET
  MENU_CODE = UPPER(#{code, jdbcType=VARCHAR})
, MENU_NM = #{name, jdbcType=VARCHAR}
, MENU_DC = #{description, jdbcType=VARCHAR}
, MENU_TY = #{type, jdbcType=VARCHAR}
, MENU_SORT = #{sort, jdbcType=INTEGER}
, MENU_ICON = #{icon, jdbcType=VARCHAR}
, MENU_URI = #{uri, jdbcType=VARCHAR}
, MENU_USE = UPPER(#{use, jdbcType=VARCHAR})
, UPDT_ID = UPPER(#{updateId, jdbcType=VARCHAR})
